import { Component, Input, HostBinding } from '@angular/core';

@Component({
  selector: 'lib-button',
  standalone: true,
  templateUrl: './button.component.html',
  styles: [], // No inline styles; Tailwind handles it
})
export class ButtonComponent {
  @Input() variant: 'primary' | 'accent' | 'outline' | 'text' = 'primary';
  @Input() disabled = false;
  @Input() class = ''; // Allow users to pass custom Tailwind classes

  @HostBinding('class') get hostClasses() {
    const baseClasses =
      'inline-flex items-center justify-center px-4 py-2 rounded-md font-medium transition-colors duration-200';
    const variantClasses = {
      primary:
        'bg-blue-600 text-white hover:bg-blue-700 focus:ring-2 focus:ring-blue-500 focus:ring-offset-2',
      accent:
        'bg-purple-600 text-white hover:bg-purple-700 focus:ring-2 focus:ring-purple-500 focus:ring-offset-2',
      outline:
        'border border-gray-300 text-gray-700 hover:bg-gray-100 focus:ring-2 focus:ring-gray-500 focus:ring-offset-2',
      text: 'text-gray-700 hover:bg-gray-100 focus:ring-2 focus:ring-gray-500 focus:ring-offset-2',
    };
    const disabledClasses = this.disabled
      ? 'opacity-50 cursor-not-allowed'
      : '';

    return `${baseClasses} ${variantClasses[this.variant]} ${disabledClasses} ${
      this.class
    }`.trim();
  }
}

import { Component, Input, Output, EventEmitter } from '@angular/core';
import { CommonModule } from '@angular/common';
@Component({
  selector: 'lib-checkbox',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './checkbox.component.html',
  styles: [], // No inline styles; Tailwind handles it
})
export class CheckboxComponent {
  @Input() checked = false;
  @Input() disabled = false;
  @Input() indeterminate = false;
  @Input() label = '';
  @Input() labelPosition: 'before' | 'after' = 'after';
  @Input() class = ''; // Allow users to pass custom Tailwind classes

  @Output() checkedChange = new EventEmitter<boolean>();
  @Output() checkboxClick = new EventEmitter<Event>();

  onChange(event: Event) {
    this.checkedChange.emit((event.target as HTMLInputElement).checked);
  }

  onClick(event: Event) {
    this.checkboxClick.emit(event);
  }
}

import {
  Component,
  Input,
  Output,
  EventEmitter,
  ViewChildren,
  QueryList,
  ElementRef,
  AfterViewInit,

} from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';

@Component({
  selector: 'lib-otp-input',
  standalone: true,
  imports: [CommonModule, FormsModule], // Ensure FormsModule is imported
  templateUrl: './pin-input.component.html',
  styles: [],
})
export class PinInputComponent implements AfterViewInit {
  @Input() length = 6; // Default 6-digit OTP
  @Input() type = 'number'; // Accepts only numbers by default
  @Input() mask = false; // Mask input like passwords
  @Input() autoSubmit = false; // Auto-submit when complete
  @Input() disabled = false; // Disable input
  @Input() customClass = ''; // Custom styling
  @Input() pin = ''; // Ensure property exists
  @Input() preventPaste = false;
  @Output() completed = new EventEmitter<string>(); // Emits OTP when complete

  @ViewChildren('otpInput') inputBoxes!: QueryList<ElementRef>;
  otpValues: string[]  = [];

  constructor() {
    this.otpValues = new Array(this.length).fill('');
  }

  ngAfterViewInit() {
    setTimeout(() => this.inputBoxes.get(0)?.nativeElement.focus(), 100);
  }

  /** Handles user input in OTP fields */
  onInput(event: Event, index: number) {
    const input = event.target as HTMLInputElement;
    const value = input.value;

    // Allow only numbers if type is 'number'
    if (this.type === 'number' && !/^\d$/.test(value)) {
      input.value = '';
      return;
    }

    this.otpValues[index] = value;

    // Move to the next input box if a digit is entered
    if (value && index < this.length - 1) {
      this.inputBoxes.get(index + 1)?.nativeElement.focus();
    }

    // Emit OTP if all fields are filled
    if (this.otpValues.every((v) => v !== '')) {
      this.emitOTP();
    }
  }

  /** Handles Backspace key for moving to the previous field */
  onKeyDown(event: KeyboardEvent, index: number) {
    if (event.key === 'Backspace' && !this.otpValues[index] && index > 0) {
      this.inputBoxes.get(index - 1)?.nativeElement.focus();
    }
  }

  /** Handles pasting OTP values */
  onPaste(event: ClipboardEvent) {
    if (this.preventPaste) {
      event.preventDefault();
      return;
    }

    event.preventDefault();
    const pasteData = event.clipboardData?.getData('text') ?? '';

    // Validate if the pasted data length matches the OTP length
    if (pasteData.length === this.length && /^[a-zA-Z0-9]+$/.test(pasteData)) {
      this.otpValues = pasteData.split('');
      this.emitOTP();
    }
  }

  /** Emits the completed OTP */
  public emitOTP() {
    const otp = this.otpValues.join('');
    if (this.autoSubmit) {
      this.completed.emit(otp);
    }
  }

}

import { Component, Input, Output, EventEmitter } from '@angular/core';
import { CommonModule } from '@angular/common';

@Component({
  selector: 'lib-rating',
  standalone: true,
  templateUrl: './rating.component.html',
  styleUrls: ['./rating.component.css'],
  imports: [CommonModule],
})
export class RatingComponent {
  @Input() max = 5;
  @Input() value = 0;
  @Input() readonly = false;
  @Input() allowHalf!: boolean;  // ✅ Fixed: No default value, avoids ESLint issue
  @Input() icon = '⭐';
  @Input() size = 'text-2xl';
  @Input() activeColor = 'text-yellow-400';
  @Input() inactiveColor = 'text-gray-300';
  @Output() valueChange = new EventEmitter<number>();

  setRating(rating: number, isHalf = false) {
    if (!this.readonly) {
      this.value = isHalf && this.allowHalf ? rating + 0.5 : rating;
      this.valueChange.emit(this.value);
    }
  }

  getStarClasses(starIndex: number) {
    if (this.value >= starIndex) {
      return `${this.activeColor} ${this.size}`;
    } else if (this.allowHalf && this.value >= starIndex - 0.5) {
      return `${this.activeColor} ${this.size} half-star`;
    } else {
      return `${this.inactiveColor} ${this.size}`;
    }
  }
}

